// Composio: fuehrt ein Tool aus 1000+ Apps (Gmail, Slack, GitHub, Notion ...) ueber die Composio-API aus.
// OAuth/App-Verbindungen verwaltet Composio (im Composio-Dashboard); hier nur Key + Tool ausfuehren.
async function run(input) {
  const apiKey = String((input && (input.api_key || input.apiKey)) || '').trim();
  const action = String((input && input.action) || '').trim();
  if (!apiKey) return { fehler: 'Composio API-Key fehlt. Bitte in den Add-on-Einstellungen hinterlegen (app.composio.dev).' };
  if (!action) return { fehler: 'Bitte das Tool angeben (action), z. B. GMAIL_SEND_EMAIL.' };
  const url = 'https://backend.composio.dev/api/v3/tools/execute/' + encodeURIComponent(action);
  const payload = { arguments: (input && input.arguments) || {}, user_id: String((input && (input.user_id || input.userId)) || 'default') };
  if (input && input.connected_account_id) payload.connected_account_id = String(input.connected_account_id);
  try {
    const res = await fetch(url, { method: 'POST', headers: { 'content-type': 'application/json', 'x-api-key': apiKey }, body: JSON.stringify(payload) });
    let data; try { data = await res.json(); } catch (e) { data = await res.text(); }
    if (!res.ok) return { fehler: 'Composio-Fehler ' + res.status, status: res.status, daten: data };
    const erfolg = data && typeof data.successful !== 'undefined' ? data.successful : res.ok;
    const ergebnis = data && typeof data.data !== 'undefined' ? data.data : data;
    return { ok: true, erfolgreich: erfolg, ergebnis: ergebnis };
  } catch (e) {
    return { fehler: 'Composio nicht erreichbar: ' + String((e && e.message) || e) };
  }
}
